#include <bits/stdc++.h>
using namespace std;
struct ListNode {
    int val;
    ListNode *next;
    ListNode *prev;
    ListNode(int x) : val(x), next(NULL), prev(NULL) {}
};
int main() {
    int n;
    cin >> n;
    ListNode* head = NULL;
    ListNode* prev_node = NULL;
    for (int i = 0; i < n; i++) {
        int val;
        cin >> val;
        ListNode* node = new ListNode(val);
        if (!head) {
            head = node;
        } else {
            node->prev = prev_node;
            prev_node->next = node;
        }
        prev_node = node;
    }
    ListNode* prev = NULL;
    ListNode* current = head;
    while (current) {
        ListNode* next_node = current->next;
        current->next = prev;
        current->prev = next_node;
        prev = current;
        current = next_node;
    }
    head = prev;
    vector<int> result;
    while (head) {
        result.push_back(head->val);
        head = head->next;
    }
    for (int i = 0; i < result.size(); i++) {
        cout << result[i];
        if (i != result.size() - 1) {
            cout << ' ';
        }
    }
    return 0;
}
